import React from 'react';
import axios from 'axios';

function NoteList({ notes, fetchNotes }) {
  const deleteNote = async (id) => {
    try {
      await axios.delete(`http://localhost:5001/api/notes/${id}`);
      fetchNotes();
    } catch (err) {
      console.error("Delete failed:", err);
    }
  };

  return (
    <div className="notes-grid">
      {notes.length === 0 ? (
        <div className="empty-state">
          <p>No notes found. Secure your first thought in the vault!</p>
        </div>
      ) : (
        notes.map((note) => (
          <div key={note._id} className="note-card">
            <div className="card-header">
              <span className="category-tag">Documentation</span>
              <span className="date-tag">
                {note.createdAt ? new Date(note.createdAt).toLocaleDateString() : 'Just now'}
              </span>
            </div>

            <div className="note-body">
              <h3 className="note-title">{note.title}</h3>
              <p className="note-content">{note.content}</p>
            </div>

            <div className="card-footer">
              <button 
                className="delete-btn" 
                onClick={() => deleteNote(note._id)}
                title="Delete note"
              >
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M3 6h18m-2 0v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6m3 0V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2" />
                </svg>
                Delete
              </button>
            </div>
          </div>
        ))
      )}
    </div>
  );
}

export default NoteList;
